#include <stdio.h>
#include <string.h>
#define MOD 42424242

int countEquivalentStrings(char *s) {
    int n = strlen(s);
    int count = 1;
    for (int i = 0; i < n; i++) {
        count = (count * 26) % MOD;
    }
    return count;
}

int main() {
    int T;
    scanf("%d", &T);
    for (int t = 0; t < T; t++) {
        char s[100001];
        scanf("%s", s);
        printf("%d\n", countEquivalentStrings(s));
    }
    return 0;
}

